#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    const char *path = "/tmp/kf_read_blocks.txt";
    int fd = open(path, O_CREAT | O_WRONLY | O_TRUNC, 0644);
    write(fd, "AABBCCDDEE", 10);
    close(fd);
    fd = open(path, O_RDONLY);
    char block[5];
    ssize_t n;
    int count = 0;
    while ((n = read(fd, block, 4)) > 0) {
        block[n] = '\0';
        count++;
        printf("Block %d: [%s] (%zd bytes)\n", count, block, n);
    }
    printf("Total blocks: %d\n", count);
    close(fd);
    unlink(path);
    return 0;
}

